et=0}end type LoaderImpl={__index:LoaderImpl,new:()->LoaderInstance,setStatus:(self:LoaderInstance,text:any)->(),setProgress:(self:LoaderInstance,p:number)->(),finish:(self:LoaderInstance,callback:(()->())?)->(),destroy:(self:LoaderInstance)->()}export type LoaderInstance={_progress:number,_currentProgress:number,_lastPct:number,_cat:CatData,_paws:{PawData},_conns:{RBXScriptConnection},_blur:BlurEffect,_gui:ScreenGui,_overlay:Frame,_status:TextLabel,_fill:Frame,_pct:TextLabel}local Loader:LoaderImpl={}::LoaderImpl Loader.__index=Loader function Loader.new():LoaderInstance local self=setmetatable({},Loader)::any self._progress=0 self._currentProgress=0 self._lastPct=-1 self._paws={}self._conns={}local camera=workspace.CurrentCamera local viewport=camera and camera.ViewportSize or Vector2.new(1920,1080)local isMobile=UserInputService.TouchEnabled and not UserInputService.KeyboardEnabled local isSmall=isMobile or viewport.X<768 or viewport.Y<500 local scale=isSmall and 0.6 or 1.0 local labelWidth=isSmall and 280 or 400 local trackWidth=isSmall and 240 or 320 local blur=Instance.new("BlurEffect")blur.Name="Neko_HubLoadBlur"blur.Size=0 blur.Parent=Lighting self._blur=blur TweenService:Create(blur,TweenInfo.new(0.35),{Size=18}):Play()local gui=Instance.new("ScreenGui")gui.Name="Neko_HubLoader"gui.ResetOnSpawn=false gui.IgnoreGuiInset=true gui.DisplayOrder=100000 gui.ZIndexBehavior=Enum.ZIndexBehavior.Sibling gui.Parent=getParentGui()self._gui=gui local overlay=Instance.new("Frame")overlay.Name="Overlay"overlay.Size=UDim2.fromScale(1,1)overlay.BackgroundColor3=COL.overlay overlay.BackgroundTransparency=1 overlay.BorderSizePixel=0 overlay.Parent=gui self._overlay=overlay TweenService:Create(overlay,TweenInfo.new(0.3),{BackgroundTransparency=0.35}):Play()local stage=Instance.new("Frame")stage.Name="Stage"stage.AnchorPoint=Vector2.new(0.5,0.5)stage.Position=UDim2.fromScale(0.5,0.40)stage.Size=UDim2.fromOffset(0,0)stage.BackgroundTransparency=1 stage.Parent=overlay self._cat=m