er)cat.bounce=(cat.bounce+dt*10)%(math.pi*2)local bounceY=math.sin(cat.bounce)*6*cat.scale cat.frame.Position=UDim2.new(0.5,0,0.5,bounceY)cat.tailWag=(cat.tailWag+dt*5)%(math.pi*2)cat.tail.Rotation=math.sin(cat.tailWag)*20 cat.leftEar.Rotation=45+math.sin(cat.bounce*2)*4 cat.rightEar.Rotation=-45-math.sin(cat.bounce*2)*4 cat.blinkTimer=cat.blinkTimer+dt local blinkInterval=3.0 local blinkDuration=0.15 if cat.blinkTimer>blinkInterval then local phase=(cat.blinkTimer-blinkInterval)/blinkDuration if phase<1 then local eyeH=math.max(1,9*cat.scale*math.abs(math.cos(phase*math.pi)))cat.leftEye.Size=UDim2.fromOffset(7*cat.scale,eyeH)cat.rightEye.Size=UDim2.fromOffset(7*cat.scale,eyeH)local hlT=math.abs(math.cos(phase*math.pi))cat.leftHL.BackgroundTransparency=hlT cat.rightHL.BackgroundTransparency=hlT else cat.blinkTimer=0 cat.leftEye.Size=UDim2.fromOffset(7*cat.scale,9*cat.scale)cat.rightEye.Size=UDim2.fromOffset(7*cat.scale,9*cat.scale)cat.leftHL.BackgroundTransparency=0 cat.rightHL.BackgroundTransparency=0 end end for _,paw in ipairs(paws)do paw.offset=paw.offset-pawSpeed*dt if paw.offset<-pawSp then paw.offset=paw.offset+pawSp*4 end paw.frame.Position=UDim2.fromOffset(paw.offset,pY)local dist=math.abs(paw.offset)local trans=0.15+math.min(dist,maxDist)/maxDist*0.85 for _,child in ipairs(paw.children)do child.BackgroundTransparency=trans end end local current=self._currentProgress local target=self._progress if current~=target then local nextProgress=current+(target-current)*(1-0.5^(dt*20))if math.abs(target-nextProgress)<0.001 then nextProgress=target end self._currentProgress=nextProgress fill.Size=UDim2.fromScale(nextProgress,1)local pctVal=math.floor(nextProgress*100+0.5)if self._lastPct~=pctVal then self._lastPct=pctVal pct.Text=tostring(pctVal).."%"end end end)table.insert(self._conns,conn)return self end function Loader:setStatus(text:any)if self._status then self._status.Text=tostring(text)end end function Loader:setProgress(p:number)self._progress=math.clamp(p,0