ogic/12_match_notif")local logic=loadModule("Neko_HubGui/Logic/13_init_config")local Shared=loadModule("Neko_HubGui/Logic/shared")if type(logic)~="table"and type(Shared)=="table"then logic=Shared.Logic end if type(logic)~="table"and getgenv then logic=getgenv().Neko_HubLogic end if type(logic)~="table"then error("[Neko_Hub] Logic table missing (check 09_logic_api / 13_init_config)")end if getgenv then getgenv().Neko_HubLogic=logic getgenv().Neko_HubShared=Shared getgenv().Neko_HubLoader={version=LOADER_VERSION,mode="require+shared",has=function(key:string):boolean return type(Shared)=="table"and Shared[key]~=nil end,get=function(key:string):any return if type(Shared)=="table"then Shared[key]else nil end,}end return logic end EmbeddedModules["Neko_HubGui/Logic/shared"]=function()export type SharedStore={[string]:any}local Shared:SharedStore={}return Shared end EmbeddedModules["Neko_HubGui/Logic/08_player"]=function()local Shared=loadModule("Neko_HubGui/Logic/shared")local Lighting=game:GetService("Lighting")local RunService=Shared.RunService local LocalPlayer=Shared.LocalPlayer local Players=Shared.Players local PlayerGui=Shared.PlayerGui Shared.PlayerConfig={UnlimitedZoom=false,MaxDistance=1000,MinDistance=0,FOVEnabled=false,FOV=70,DefaultFOV=workspace.CurrentCamera.FieldOfView,Fullbright=false,}local fovConn:RBXScriptConnection?=nil local function ensureFovLoop()if Shared.PlayerConfig.FOVEnabled then if not fovConn then fovConn=RunService.RenderStepped:Connect(function()local cfg=Shared.PlayerConfig if not cfg.FOVEnabled then return end local cam=workspace.CurrentCamera if cam and cam.FieldOfView~=cfg.FOV then cam.FieldOfView=cfg.FOV end end)end elseif fovConn then fovConn:Disconnect()fovConn=nil end end function Shared.applyUnlimitedZoom()if Shared.PlayerConfig.UnlimitedZoom then LocalPlayer.CameraMaxZoomDistance=Shared.PlayerConfig.MaxDistance LocalPlayer.CameraMinZoomDistance=Shared.PlayerConfig.MinDistance else LocalPlayer.CameraMaxZoomDistance=128 LocalPlayer.